(function(){'use strict';const IDLE_TIMEOUT_MS=10800000,PROMPT_TIMEOUT_MS=60000,MODAL_ID='jf-sleep-timer-modal';let idleTimer=null,promptTimer=null,isPromptActive=false,lastVideoRef=null;const ensureStyles=()=>{if(document.getElementById('jf-sleep-style'))return;const style=document.createElement('style');style.id='jf-sleep-style';style.textContent=`#${MODAL_ID}{position:fixed;top:0;left:0;width:100vw;height:100vh;background:rgba(0,0,0,0.85);backdrop-filter:blur(10px);z-index:99999;display:flex;flex-direction:column;align-items:center;justify-content:center;color:#fff;font-family:sans-serif;opacity:0;pointer-events:none;transition:opacity .3s ease}#${MODAL_ID}.active{opacity:1;pointer-events:auto}.jf-sleep-title{font-size:2.2rem;font-weight:600;margin-bottom:2.5rem;text-shadow:0 4px 10px rgba(0,0,0,0.5)}.jf-sleep-btn{background:var(--active-color,#10b981);color:#fff;border:none;padding:16px 40px;font-size:1.25rem;border-radius:8px;cursor:pointer;font-weight:700;text-transform:uppercase;letter-spacing:1px;box-shadow:0 4px 15px rgba(0,0,0,0.4);transition:transform .2s,background .2s,filter .2s}.jf-sleep-btn:hover{filter:brightness(1.1);transform:scale(1.05)}`;document.head.appendChild(style)};const createModal=()=>{if(document.getElementById(MODAL_ID))return;ensureStyles();const modal=document.createElement('div');modal.id=MODAL_ID;const title=document.createElement('div');title.className='jf-sleep-title';title.textContent='Are you still watching?';const btn=document.createElement('button');btn.className='jf-sleep-btn';btn.textContent='Continue Watching';btn.addEventListener('click',()=>dismissPrompt());modal.appendChild(title);modal.appendChild(btn);document.body.appendChild(modal)};const exitPlayer=()=>{const backBtn=document.querySelector('.btnHeaderBack')||document.querySelector('.videoOsdBack');if(backBtn)backBtn.click();else window.history.back();dismissPrompt()};const showPrompt=()=>{const video=document.querySelector('video');if(!video||video.paused)return;isPromptActive=true;video.pause();createModal();const modal=document.getElementById(MODAL_ID);modal.classList.add('active');promptTimer=setTimeout(()=>exitPlayer(),PROMPT_TIMEOUT_MS)};const dismissPrompt=()=>{isPromptActive=false;if(promptTimer)clearTimeout(promptTimer);const modal=document.getElementById(MODAL_ID);if(modal)modal.classList.remove('active');const video=document.querySelector('video');if(video&&video.paused)video.play().catch(()=>{});resetIdleTimer()};const resetIdleTimer=()=>{if(idleTimer)clearTimeout(idleTimer);if(isPromptActive)return;const video=document.querySelector('video');if(video&&!video.paused)idleTimer=setTimeout(()=>showPrompt(),IDLE_TIMEOUT_MS)};const handleActivity=()=>{if(!isPromptActive)resetIdleTimer()};const initListeners=()=>{['mousemove','mousedown','keydown','touchstart','scroll'].forEach(evt=>window.addEventListener(evt,handleActivity,{passive:true}))};const checkPlayerState=()=>{const video=document.querySelector('video');if(video!==lastVideoRef){if(lastVideoRef){lastVideoRef.removeEventListener('play',resetIdleTimer);lastVideoRef.removeEventListener('pause',handleActivity)}lastVideoRef=video;if(video){video.addEventListener('play',resetIdleTimer);video.addEventListener('pause',handleActivity);resetIdleTimer()}else{if(idleTimer)clearTimeout(idleTimer);if(isPromptActive)dismissPrompt()}}};const init=()=>{initListeners();checkPlayerState();new MutationObserver(checkPlayerState).observe(document.body,{childList:true,subtree:true})};if(document.readyState==='complete'||document.readyState==='interactive')init();else window.addEventListener('DOMContentLoaded',init)})();
